EDITS = [
    ('countries data + label layer',
     'map.addLayer({id:"borders",type:"line",source:"world",\n    paint:{"line-color":"#05080f","line-width":0.5,"line-opacity-transition":{duration:400}}});',
     'map.addLayer({id:"borders",type:"line",source:"world",\n    paint:{"line-color":"#05080f","line-width":0.5,"line-opacity-transition":{duration:400}}});\n  MAPDATA.features.forEach(function(f,i){ f.properties.color_countries = COUNTRY_PASTEL[i]; });\n  map.addSource("country-labels",{type:"geojson",data:COUNTRY_LABELS});\n  map.addLayer({id:"country-labels",type:"symbol",source:"country-labels",\n    layout:{"text-field":["get","name"],"text-font":["Open Sans Regular"],\n      "text-size":["get","size"],"text-max-width":7,"text-padding":2,\n      "symbol-placement":"point","text-allow-overlap":false,"visibility":"none"},\n    paint:{"text-color":"#3a3226","text-halo-color":"rgba(255,255,255,0.55)","text-halo-width":1.1}});',
     'country-labels'),
    ('META layer entry',
     '"layers":[{"group":"Belief"',
     '"layers":[{"group":"Reference","key":"countries","label":"Countries","type":"reference"},{"group":"Belief"',
     '"key":"countries"'),
    ('setLayer visibility hook',
     'updateNoDataHatch(key);',
     'updateNoDataHatch(key);\n  if(map.getLayer("country-labels")) map.setLayoutProperty("country-labels","visibility", key==="countries"?"visible":"none");',
     'key==="countries"?"visible":"none"'),
    ('legend reference-type branch',
     '} else if(c.type==="categorical"){',
     '} else if(c.type==="reference"){\n    b+=`<div class="lg-row" style="font-size:12px">Countries shaded for visual distinction only - adjoining countries never share a color. Color carries no data.</div>`;\n  } else if(c.type==="categorical"){',
     'c.type==="reference"'),
]

# splice the two baked JS constants in right before the map is constructed
ANCHOR = "/* ---------------- Map ---------------- */"
INJECT = "const COUNTRY_PASTEL=" + COUNTRY_PASTEL + ";\nconst COUNTRY_LABELS=" + COUNTRY_LABELS + ";\n" + ANCHOR
if "const COUNTRY_PASTEL=" not in text:
    if ANCHOR not in text:
        print("  [ ANCHOR-NOT-FOUND] baked data constants"); sys.exit(1)
    text = text.replace(ANCHOR, INJECT, 1)
    print("  [        patched] baked data constants")
else:
    print("  [already-applied] baked data constants")

res = []
for name, old, new, sentinel in EDITS:
    if sentinel in text:
        res.append((name, "already-applied"))
    elif old in text:
        text = text.replace(old, new, 1)
        res.append((name, "patched"))
    else:
        res.append((name, "ANCHOR-NOT-FOUND"))

open(OUT, "w", encoding="utf-8").write(text)
ok = all(s in ("patched", "already-applied") for _, s in res)
for name, s in res:
    print(f"  [{s:>16}] {name}")
print("OK: Countries reference layer applied" if ok else "WARN: an anchor was not found")
sys.exit(0 if ok else 1)
